import{_ as r,c as o,o as s,ag as n}from"./chunks/framework.XjE0kKti.js";const a="/gatewayweb/docs/assets/hub0023-log-query.bTX2jQXN.png",d="/gatewayweb/docs/assets/hub0023-log-context-menu.-PQCGibK.png",e="/gatewayweb/docs/assets/hub0023-resend-dialog.YxWzBvc_.png",g="/gatewayweb/docs/assets/hub0023-monitor-trends.DZQhukWw.png",l="/gatewayweb/docs/assets/hub0023-monitor-overview.BdP9fdI_.png",q=JSON.parse('{"title":"网关日志管理（hub0023）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0023.md","filePath":"modules/hub0023.md","lastUpdated":null}'),h={name:"modules/hub0023.md"};function i(b,t,c,u,p,m){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="网关日志管理-hub0023" tabindex="-1">网关日志管理（hub0023） <a class="header-anchor" href="#网关日志管理-hub0023" aria-label="Permalink to &quot;网关日志管理（hub0023）&quot;">​</a></h1><p>按<strong>网关实例</strong>查询与浏览访问日志，支持条件筛选、导出、单条详情（含后端追踪）、请求重发，以及同一实例维度下的<strong>监控图表</strong>（概览与趋势）。日志数据按实例分片存储，因此<strong>列表、导出、详情与监控类查询都必须指定网关实例</strong>（界面中的「实例名称」会同步绑定后端的 <code>gatewayInstanceId</code>）。</p><p><img src="'+a+'" alt="日志查询主界面"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>日志查询</td><td>按时间范围、实例、路由、服务、耗时等条件分页查询访问日志。</td></tr><tr><td>详情与追踪</td><td>打开「后端日志详情」对话框，查看主表信息与后端服务追踪链。</td></tr><tr><td>导出</td><td>按当前查询条件导出；仍受所选实例约束。</td></tr><tr><td>批量重发</td><td>将勾选的多条日志载入「请求重发」弹窗；单次最多 <strong>100</strong> 条，超出部分不会进入弹窗。</td></tr><tr><td>监控图表</td><td>在选定时间粒度下查看总请求、成功/失败、响应时间以及请求量与耗时趋势等。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>网关管理</strong> → <strong>网关日志管理</strong>。</p><p>页面为左侧标签布局：</p><ul><li><strong>日志查询</strong>：主列表与筛选、工具栏、表格右键菜单。</li><li><strong>监控图表</strong>：在同一模块内切换，筛选条件与日志页类似，但<strong>时间范围不得超过 24 小时</strong>（表单校验）。</li></ul><hr><h2 id="日志查询" tabindex="-1">日志查询 <a class="header-anchor" href="#日志查询" aria-label="Permalink to &quot;日志查询&quot;">​</a></h2><h3 id="必填条件" tabindex="-1">必填条件 <a class="header-anchor" href="#必填条件" aria-label="Permalink to &quot;必填条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><strong>时间范围</strong></td><td>按网关开始处理时间筛选；支持快捷项（今天、昨天、最近 1/6/24 小时、最近 7 天等，以界面为准）。</td></tr><tr><td><strong>实例名称</strong></td><td>必选。决定查询哪套实例上的访问日志；可通过名称旁的「…」打开选择器。未选实例时，<strong>查询</strong>、<strong>导出日志</strong> 等会提示先选择实例。</td></tr></tbody></table><h3 id="主区域常用条件" tabindex="-1">主区域常用条件 <a class="header-anchor" href="#主区域常用条件" aria-label="Permalink to &quot;主区域常用条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td><strong>路由名称</strong></td><td>可输入或点击「…」从路由选择器选择；路由列表会按当前已选实例过滤。</td></tr><tr><td><strong>服务名称</strong></td><td>同上，与服务选择器联动实例。</td></tr><tr><td><strong>网关耗时</strong></td><td>「最小耗时」阈值，单位毫秒，用于筛掉耗时过低的记录。</td></tr></tbody></table><h3 id="「更多条件」展开项" tabindex="-1">「更多条件」展开项 <a class="header-anchor" href="#「更多条件」展开项" aria-label="Permalink to &quot;「更多条件」展开项&quot;">​</a></h3><p>点击 <strong>更多条件</strong> 后，还可填写：<strong>链路追踪 ID</strong>、<strong>请求路径</strong>、<strong>客户端 IP</strong>、<strong>请求方法</strong>、<strong>代理类型</strong>、<strong>状态码</strong>、<strong>后端状态码</strong>、<strong>重置状态</strong>、<strong>用户标识</strong>，以及开关 <strong>仅非 200 状态</strong>（快速只看异常响应）。</p><h3 id="工具栏与查询流程" tabindex="-1">工具栏与查询流程 <a class="header-anchor" href="#工具栏与查询流程" aria-label="Permalink to &quot;工具栏与查询流程&quot;">​</a></h3><ol><li>选择 <strong>时间范围</strong> 与 <strong>实例名称</strong>（可再填路由、服务、耗时等）。</li><li>点击 <strong>查询</strong> 刷新列表（从第一页开始）；<strong>重置</strong> 会恢复表单默认（时间仍可能默认当天、实例若接口有默认则可能保留）。</li><li><strong>更多条件</strong> 用于展开或收起上述扩展筛选项。</li></ol><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>对当前<strong>选中行</strong>（表格勾选或焦点行）打开「后端日志详情」；未选中时会提示先选择一行。</td></tr><tr><td><strong>批量重发</strong></td><td>将<strong>已勾选</strong>的多条记录打开「请求重发」；未勾选会提示选择；超过 100 条时仅前 100 条进入弹窗并给出提示。</td></tr><tr><td><strong>导出日志</strong></td><td>按当前条件导出，<strong>必须先选实例</strong>。</td></tr><tr><td><strong>查询 / 重置</strong></td><td>同常规搜索表单行为。</td></tr></tbody></table><h3 id="列表列与含义-常见列" tabindex="-1">列表列与含义（常见列） <a class="header-anchor" href="#列表列与含义-常见列" aria-label="Permalink to &quot;列表列与含义（常见列）&quot;">​</a></h3><p>表格以后端返回与配置为准，常见列包括：</p><table tabindex="0"><thead><tr><th>列</th><th>含义</th></tr></thead><tbody><tr><td>序号</td><td>当前页内行号。</td></tr><tr><td>链路追踪 ID</td><td>全链路关联 ID，详情与重发均依赖该字段。</td></tr><tr><td>网关实例</td><td>处理该请求的网关实例名称。</td></tr><tr><td>路由名称</td><td>匹配到的路由；无则显示为 <code>-</code>。</td></tr><tr><td>请求路径</td><td>实际请求路径（可能较长，悬停可看完整内容）。</td></tr><tr><td>请求方法</td><td>HTTP 方法，以标签形式展示。</td></tr><tr><td>状态码</td><td>网关侧 HTTP 状态码（如 404、500）；颜色仅作区分，<strong>不代表</strong>处理状态列的语义。</td></tr><tr><td>处理状态</td><td>网关内部处理生命周期（如已完成等），与 HTTP 状态码独立。</td></tr><tr><td>总处理时间</td><td>端到端耗时，单位毫秒。</td></tr><tr><td>开始时间</td><td>请求开始时间。</td></tr></tbody></table><h3 id="表格右键菜单" tabindex="-1">表格右键菜单 <a class="header-anchor" href="#表格右键菜单" aria-label="Permalink to &quot;表格右键菜单&quot;">​</a></h3><p>在数据行上右键，除表格组件自带的 <strong>复制行数据</strong>、<strong>复制单元格外</strong>，还可：</p><p><img src="'+d+'" alt="日志列表右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>与工具栏「查看详情」相同，针对<strong>右键所在行</strong>。</td></tr><tr><td><strong>重发</strong></td><td>仅针对该行打开「请求重发」（与批量入口为同一弹窗，列表中可含单条）。</td></tr></tbody></table><p>工具栏「查看详情」依赖<strong>当前选中行</strong>；右键「查看详情」针对<strong>右键那一行</strong>。若习惯点选一行再操作，两种方式等价。</p><hr><h2 id="详情与请求重发" tabindex="-1">详情与请求重发 <a class="header-anchor" href="#详情与请求重发" aria-label="Permalink to &quot;详情与请求重发&quot;">​</a></h2><h3 id="后端日志详情" tabindex="-1">后端日志详情 <a class="header-anchor" href="#后端日志详情" aria-label="Permalink to &quot;后端日志详情&quot;">​</a></h3><ul><li>依赖该行的 <strong>traceId</strong> 与 <strong>gatewayInstanceId</strong>。若数据不完整，界面会提示从列表重新打开。</li><li>对话框标题形如：<code>后端日志详情 - &lt;TraceId&gt;</code>。</li><li>内容分区包括：<strong>基本信息</strong>、<strong>请求信息</strong>、<strong>响应信息</strong>、<strong>时间跟踪</strong>、<strong>路由信息</strong> 等；若有错误、请求/响应头体，会按需展示。</li><li>下方 <strong>后端服务追踪</strong> 以多 Tab 展示各后端跳转，含转发信息、时间、响应及可选的转发体、响应体等。</li></ul><h3 id="请求重发弹窗" tabindex="-1">请求重发弹窗 <a class="header-anchor" href="#请求重发弹窗" aria-label="Permalink to &quot;请求重发弹窗&quot;">​</a></h3><p>从 <strong>批量重发</strong>（多选）或右键 <strong>重发</strong>（单条）进入。</p><p><img src="'+e+'" alt="请求重发"></p><ul><li><strong>左侧「重发列表（TraceId）」</strong>：本次带入的所有 Trace；可切换查看每一条的拼装结果。卡片上会显示 <strong>重发状态</strong>、<strong>响应状态</strong> 等摘要。</li><li><strong>自动发送</strong>：按列表顺序对尚未自动执行过的条目依次加载并发送（适合批量回归；请注意对下游环境的冲击）。</li><li><strong>右侧</strong>：类似 HTTP 调试客户端，可切换 <strong>Params / Body / Headers / Cookies / Auth</strong>，修改后点击 <strong>发送</strong> 手动重放。</li><li><strong>响应</strong> 区域展示本次重发的响应 Body 与 Headers。</li><li><strong>取消</strong> 关闭弹窗；全屏按钮可放大编辑区域。</li></ul><p>重发数据来自该条日志的详情接口拼装，用于排障与复现；修改参数后发送的是<strong>新请求</strong>，请谨慎在生产环境使用。</p><hr><h2 id="监控图表" tabindex="-1">监控图表 <a class="header-anchor" href="#监控图表" aria-label="Permalink to &quot;监控图表&quot;">​</a></h2><p>切换到 <strong>监控图表</strong> 标签后，先选择 <strong>时间范围</strong>（<strong>必填，且跨度不超过 24 小时</strong>）、<strong>时间粒度</strong>（按分钟 / 按小时 / 按天）、<strong>实例名称</strong>，可选 <strong>路由名称</strong>、<strong>请求路径</strong>，再点击 <strong>查询</strong>。</p><p>工具栏 <strong>刷新数据</strong> 会在保持当前表单条件的情况下重新拉取监控接口数据。</p><h3 id="监控概览" tabindex="-1">监控概览 <a class="header-anchor" href="#监控概览" aria-label="Permalink to &quot;监控概览&quot;">​</a></h3><p>展示 <strong>总请求数</strong>、<strong>成功请求数</strong>、<strong>失败请求数</strong>，以及 <strong>平均 / 最小 / 最大响应时间</strong>（毫秒）。用于快速判断所选时段内流量规模与延迟水平。</p><h3 id="图表说明" tabindex="-1">图表说明 <a class="header-anchor" href="#图表说明" aria-label="Permalink to &quot;图表说明&quot;">​</a></h3><p><img src="'+g+'" alt="监控趋势与概览指标"></p><ul><li><strong>请求量趋势（按当前粒度）</strong>：单位时间内请求条数随时间变化，用于看流量高峰与低谷。</li><li><strong>响应时间趋势（按当前粒度）</strong>：通常包含平均、P50、P90、P99 等曲线；<strong>P99</strong> 表示 99% 的请求耗时低于该值，对长尾延迟敏感。</li><li>若界面提供图表区分页或轮播（如 <strong>1/2</strong>），可切换查看其余监控图。</li></ul><p><img src="'+l+'" alt="请求指标、状态码分布与热点路由"></p><ul><li><strong>请求指标分布</strong>：成功与失败请求占比（例如失败占比升高时需结合日志查询排查）。</li><li><strong>状态码分布</strong>：各 HTTP 状态码占比（如 404、502 集中时需检查路由或上游）。</li><li><strong>热点路由 TOP10</strong>：访问量最高的路由排行，便于发现热点路径与容量规划。</li></ul><hr><h2 id="使用建议与说明" tabindex="-1">使用建议与说明 <a class="header-anchor" href="#使用建议与说明" aria-label="Permalink to &quot;使用建议与说明&quot;">​</a></h2><ul><li><strong>先选实例再查</strong>：与存储分片一致，避免误查或空结果。</li><li><strong>日志查询</strong> 与 <strong>监控图表</strong> 的时间含义均为网关侧时间范围；监控页额外限制 <strong>24 小时</strong>，避免单次聚合压力过大。</li><li><strong>状态码</strong>（HTTP）与 <strong>处理状态</strong>（网关内部）同时出现时，排查问题建议两者对照，并结合详情中的后端追踪。</li></ul><hr><h2 id="开发与数据约定-简述" tabindex="-1">开发与数据约定（简述） <a class="header-anchor" href="#开发与数据约定-简述" aria-label="Permalink to &quot;开发与数据约定（简述）&quot;">​</a></h2><p>面向二次开发时：网关日志相关 API 在发请求前会校验 <strong>gatewayInstanceId</strong>（去空白后非空）；缺失时由前端拦截并提示用户。列表、详情、导出、监控概览与图表等查询均携带实例维度。重置类写操作参数以后端定义为准。</p>',56)])])}const _=r(h,[["render",i]]);export{q as __pageData,_ as default};
